async (params, browser) => {
  // Open Discogs
  await browser.open(`https://www.discogs.com/release/${params.release_id}`)

  // Wait for page
  await browser.waitForSelector('.profile, h1, #release-title', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const title = document.querySelector('h1, #release-title')?.textContent?.trim() || ''; const artists = []; document.querySelectorAll('#profile_title a[href*="/artist/"]').forEach(a => artists.push(a.textContent?.trim())); const tracks = []; document.querySelectorAll('.tracklist_track, tr[class*="track"]').forEach(t => { const pos = t.querySelector('.tracklist_track_pos, td:first-child')?.textContent?.trim() || ''; const name = t.querySelector('.tracklist_track_title a, .trackTitle')?.textContent?.trim() || ''; const dur = t.querySelector('.tracklist_track_duration span, td:last-child')?.textContent?.trim() || ''; tracks.push({ position: pos, name, duration: dur }); }); const rating = document.querySelector('.rating_value, .average')?.textContent?.trim() || ''; return { title, artists, tracks, rating, url: window.location.href };`)

  return result
}
